  1→// @vitest-environment jsdom
  2→import "@testing-library/jest-dom/vitest";
  3→import { render, screen } from "@testing-library/react";
  4→import userEvent from "@testing-library/user-event";
  5→import { beforeAll, describe, expect, test, vi } from "vitest";
  6→
  7→import { BLOCK_DEFAULTS, BlockInserter } from "./block-inserter";
  8→
  9→// ---------------------------------------------------------------------------
 10→// Radix UI Polyfills (required for jsdom)
 11→// ---------------------------------------------------------------------------
 12→
 13→beforeAll(() => {
 14→  Element.prototype.hasPointerCapture ??= vi.fn().mockReturnValue(false);
 15→  Element.prototype.setPointerCapture ??= vi.fn();
 16→  Element.prototype.releasePointerCapture ??= vi.fn();
 17→  Element.prototype.scrollIntoView ??= vi.fn();
 18→});
 19→
 20→// ---------------------------------------------------------------------------
 21→// Tests
 22→// ---------------------------------------------------------------------------
 23→
 24→describe("BlockInserter", () => {
 25→  test("renders add-block button", () => {
 26→    render(<BlockInserter blockIndex={0} onInsertBlock={vi.fn()} />);
 27→
 28→    expect(
 29→      screen.getByRole("button", { name: /block hinzufügen/i }),
 30→    ).toBeInTheDocument();
 31→  });
 32→
 33→  test("click on + button opens block type menu", async () => {
 34→    const user = userEvent.setup();
 35→    render(<BlockInserter blockIndex={0} onInsertBlock={vi.fn()} />);
 36→
 37→    await user.click(screen.getByRole("button", { name: /block hinzufügen/i }));
 38→
 39→    expect(screen.getByRole("menu")).toBeInTheDocument();
 40→    expect(
 41→      screen.getByRole("menuitem", { name: /paragraph/i }),
 42→    ).toBeInTheDocument();
 43→    expect(
 44→      screen.getByRole("menuitem", { name: /heading.*h2/i }),
 45→    ).toBeInTheDocument();
 46→    expect(
 47→      screen.getByRole("menuitem", { name: /heading.*h3/i }),
 48→    ).toBeInTheDocument();
 49→    expect(screen.getByRole("menuitem", { name: /list/i })).toBeInTheDocument();
 50→    expect(screen.getByRole("menuitem", { name: /code/i })).toBeInTheDocument();
 51→    expect(
 52→      screen.getByRole("menuitem", { name: /quote/i }),
 53→    ).toBeInTheDocument();
 54→    expect(
 55→      screen.getByRole("menuitem", { name: /table/i }),
 56→    ).toBeInTheDocument();
 57→  });
 58→
 59→  test("selecting paragraph calls onInsertBlock with correct default", async () => {
 60→    const user = userEvent.setup();
 61→    const onInsertBlock = vi.fn();
 62→    render(<BlockInserter blockIndex={3} onInsertBlock={onInsertBlock} />);
 63→
 64→    await user.click(screen.getByRole("button", { name: /block hinzufügen/i }));
 65→    await user.click(screen.getByRole("menuitem", { name: /paragraph/i }));
 66→
 67→    expect(onInsertBlock).toHaveBeenCalledOnce();
 68→    expect(onInsertBlock).toHaveBeenCalledWith(
 69→      3,
 70→      expect.objectContaining(BLOCK_DEFAULTS.paragraph),
 71→    );
 72→    const insertedBlock = onInsertBlock.mock.calls[0]?.[1];
 73→    expect(insertedBlock.id).toHaveLength(8);
 74→  });
 75→
 76→  test("selecting heading h2 calls onInsertBlock with heading level 2", async () => {
 77→    const user = userEvent.setup();
 78→    const onInsertBlock = vi.fn();
 79→    render(<BlockInserter blockIndex={1} onInsertBlock={onInsertBlock} />);
 80→
 81→    await user.click(screen.getByRole("button", { name: /block hinzufügen/i }));
 82→    await user.click(screen.getByRole("menuitem", { name: /heading.*h2/i }));
 83→
 84→    expect(onInsertBlock).toHaveBeenCalledWith(
 85→      1,
 86→      expect.objectContaining(BLOCK_DEFAULTS.h2),
 87→    );
 88→  });
 89→
 90→  test("selecting heading h3 calls onInsertBlock with heading level 3", async () => {
 91→    const user = userEvent.setup();
 92→    const onInsertBlock = vi.fn();
 93→    render(<BlockInserter blockIndex={0} onInsertBlock={onInsertBlock} />);
 94→
 95→    await user.click(screen.getByRole("button", { name: /block hinzufügen/i }));
 96→    await user.click(screen.getByRole("menuitem", { name: /heading.*h3/i }));
 97→
 98→    expect(onInsertBlock).toHaveBeenCalledWith(
