import "@testing-library/jest-dom/vitest";

import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

import { TableGridPicker } from "./table-grid-picker";

// ---------------------------------------------------------------------------
// Radix UI polyfills (project convention)
// ---------------------------------------------------------------------------

beforeAll(() => {
  Element.prototype.hasPointerCapture ??= vi
    .fn()
    .mockReturnValue(false) as Element["hasPointerCapture"];
  Element.prototype.setPointerCapture ??=
    vi.fn() as Element["setPointerCapture"];
  Element.prototype.releasePointerCapture ??=
    vi.fn() as Element["releasePointerCapture"];
  Element.prototype.scrollIntoView ??= vi.fn() as Element["scrollIntoView"];
});

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("TableGridPicker", () => {
  test("renders all 48 grid cells (8×6)", () => {
    render(<TableGridPicker onSelect={vi.fn()} />);

    const cells: HTMLElement[] = [];
    for (let row = 1; row <= 6; row++) {
      for (let col = 1; col <= 8; col++) {
        const cell = screen.getByTestId(`grid-cell-${col}-${row}`);
        expect(cell).toBeInTheDocument();
        cells.push(cell);
      }
    }
    expect(cells).toHaveLength(48);
  });

  test("shows label '2 × 3' when hovering cell (2,3)", async () => {
    const user = userEvent.setup();
    render(<TableGridPicker onSelect={vi.fn()} />);

    expect(screen.queryByText("2 × 3")).not.toBeInTheDocument();

    const cell = screen.getByTestId("grid-cell-2-3");
    await user.hover(cell);

    expect(screen.getByText("2 × 3")).toBeInTheDocument();
  });

  test("calls onSelect(2, 3) when clicking cell (2,3)", async () => {
    const user = userEvent.setup();
    const onSelect = vi.fn();
    render(<TableGridPicker onSelect={onSelect} />);

    const cell = screen.getByTestId("grid-cell-2-3");
    await user.click(cell);

    expect(onSelect).toHaveBeenCalledWith(2, 3);
    expect(onSelect).toHaveBeenCalledTimes(1);
  });

  test("highlights cells up to hovered position", async () => {
    const user = userEvent.setup();
    render(<TableGridPicker onSelect={vi.fn()} />);

    const cell = screen.getByTestId("grid-cell-2-3");
    await user.hover(cell);

    // Cells within the selection (col <= 2, row <= 3) should be highlighted
    for (let row = 1; row <= 3; row++) {
      for (let col = 1; col <= 2; col++) {
        const highlighted = screen.getByTestId(`grid-cell-${col}-${row}`);
        expect(highlighted.className).toMatch(/bg-primary/);
      }
    }

    // A cell outside the selection should NOT be highlighted
    const outside = screen.getByTestId("grid-cell-3-3");
    expect(outside.className).not.toMatch(/bg-primary/);
  });

  test("no label shown in default state (no hover)", () => {
    render(<TableGridPicker onSelect={vi.fn()} />);

    // No dimension label should be visible
    expect(screen.queryByText(/\d+ × \d+/)).not.toBeInTheDocument();
  });
});

import type { Block } from "@chat-exporter/shared";
import { generateBlockId } from "@chat-exporter/shared";

type TableBlock = Extract<Block, { type: "table" }>;

export function createEmptyTable(cols: number, rows: number): TableBlock {
  return {
    id: generateBlockId(),
    type: "table",
    headers: Array.from({ length: cols }, (_, i) => `Spalte ${i + 1}`),
    rows: Array.from({ length: rows }, () => Array.from({ length: cols }, () => "")),
  };
}

export function addRow(table: TableBlock): TableBlock {
  const emptyRow = Array.from({ length: table.headers.length }, () => "");
  return { ...table, rows: [...table.rows, emptyRow] };
}

export function addColumn(table: TableBlock): TableBlock {
  const newHeader = `Spalte ${table.headers.length + 1}`;
  return {
    ...table,
    headers: [...table.headers, newHeader],
    rows: table.rows.map((row) => [...row, ""]),
  };
}

export function removeRow(table: TableBlock, rowIndex: number): TableBlock {
  if (table.rows.length <= 1) return table;
  return { ...table, rows: table.rows.filter((_, i) => i !== rowIndex) };
}

export function removeColumn(table: TableBlock, colIndex: number): TableBlock {
  if (table.headers.length <= 1) return table;
  return {
    ...table,
    headers: table.headers.filter((_, i) => i !== colIndex),
    rows: table.rows.map((row) => row.filter((_, i) => i !== colIndex)),
  };
}

export function canAddRow(table: TableBlock): boolean {
  return table.rows.length < 10;
}

export function canAddColumn(table: TableBlock): boolean {
  return table.headers.length < 10;
}

export function canRemoveRow(table: TableBlock): boolean {
  return table.rows.length > 1;
}

export function canRemoveColumn(table: TableBlock): boolean {
  return table.headers.length > 1;
}

import { useState } from "react";

import { cn } from "@/lib/utils";

interface TableGridPickerProps {
  onSelect: (cols: number, rows: number) => void;
}

const MAX_COLS = 8;
const MAX_ROWS = 6;

function TableGridPicker({ onSelect }: TableGridPickerProps) {
  const [hovered, setHovered] = useState<{ col: number; row: number } | null>(
    null,
  );

  const cells: { col: number; row: number }[] = [];
  for (let row = 1; row <= MAX_ROWS; row++) {
    for (let col = 1; col <= MAX_COLS; col++) {
      cells.push({ col, row });
    }
  }

  return (
    <div className="p-2" onMouseLeave={() => setHovered(null)}>
      <div
        className="grid gap-0.5"
        style={{ gridTemplateColumns: `repeat(${MAX_COLS}, 1fr)` }}
      >
        {cells.map(({ col, row }) => {
          const isHighlighted =
            hovered !== null && col <= hovered.col && row <= hovered.row;

          return (
            <button
              key={`${col}-${row}`}
              type="button"
              data-testid={`grid-cell-${col}-${row}`}
              className={cn(
                "h-5 w-5 rounded-sm border border-border/60",
                isHighlighted
                  ? "bg-primary/20 border-primary/40"
                  : "bg-background",
              )}
              onMouseEnter={() => setHovered({ col, row })}
              onClick={() => onSelect(col, row)}
            />
          );
        })}
      </div>
      {hovered !== null && hovered.col > 0 && hovered.row > 0 && (
        <p className="mt-1.5 text-center text-xs text-muted-foreground">
          {hovered.col} × {hovered.row}
        </p>
      )}
    </div>
  );
}

export { TableGridPicker };
export type { TableGridPickerProps };

